import {
  Body,
  Button,
  Container,
  Head,
  Heading,
  Hr,
  Html,
  Link,
  Preview,
  Section,
  Text,
} from '@react-email/components';

interface PaymentReceiptEmailProps {
  to: string;
  registrantName: string;
  tournamentName: string;
  amountCents: number;
  currency?: string;
  paymentMethod: string;
  transactionId: string;
  eventDate: string;
  receiptUrl?: string;
}

function formatCents(cents: number, currency = 'usd'): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: currency.toUpperCase(),
  }).format(cents / 100);
}

export function PaymentReceiptEmail({
  registrantName,
  tournamentName,
  amountCents,
  currency = 'usd',
  paymentMethod,
  transactionId,
  eventDate,
  receiptUrl,
}: PaymentReceiptEmailProps) {
  return (
    <Html>
      <Head />
      <Preview>Payment receipt for {tournamentName}</Preview>
      <Body style={styles.body}>
        <Container style={styles.container}>
          {/* Header */}
          <Section style={styles.header}>
            <Heading style={styles.logoText}>SPOTTER</Heading>
            <Text style={styles.headerSub}>Golf. Connected.</Text>
          </Section>

          {/* Main content */}
          <Section style={styles.main}>
            <Heading style={styles.heading}>Payment Receipt</Heading>
            <Text style={styles.greeting}>Hi {registrantName},</Text>
            <Text style={styles.text}>
              Thank you for your payment. Here is your receipt for{' '}
              <strong>{tournamentName}</strong>.
            </Text>

            {/* Receipt card */}
            <Section style={styles.receiptCard}>
              <Text style={styles.receiptTitle}>RECEIPT</Text>
              <Hr style={styles.receiptHr} />
              <div style={styles.receiptRow}>
                <Text style={styles.receiptLabel}>Event</Text>
                <Text style={styles.receiptValue}>{tournamentName}</Text>
              </div>
              <div style={styles.receiptRow}>
                <Text style={styles.receiptLabel}>Date</Text>
                <Text style={styles.receiptValue}>{eventDate}</Text>
              </div>
              <div style={styles.receiptRow}>
                <Text style={styles.receiptLabel}>Payment Method</Text>
                <Text style={styles.receiptValue}>{paymentMethod}</Text>
              </div>
              <div style={styles.receiptRow}>
                <Text style={styles.receiptLabel}>Transaction ID</Text>
                <Text style={styles.receiptMono}>{transactionId}</Text>
              </div>
              <Hr style={styles.receiptHr} />
              <div style={styles.receiptRow}>
                <Text style={styles.receiptTotalLabel}>Total Paid</Text>
                <Text style={styles.receiptTotalValue}>{formatCents(amountCents, currency)}</Text>
              </div>
            </Section>

            <Text style={styles.smallText}>
              This receipt was automatically generated by Spotter. If you have questions about your payment,
              contact <Link href="mailto:billing@spotter.golf" style={styles.link}>billing@spotter.golf</Link>.
            </Text>
          </Section>

          <Hr style={styles.hr} />
          <Section style={styles.footer}>
            <Text style={styles.footerText}>
              Spotter · 123 Golf Club Drive · Scottsdale, AZ 85251
            </Text>
            <Text style={styles.footerText}>
              <Link href="https://spotter.golf" style={styles.link}>
                spotter.golf
              </Link>
            </Text>
          </Section>
        </Container>
      </Body>
    </Html>
  );
}

const styles = {
  body: { backgroundColor: '#f5f5f5', fontFamily: 'sans-serif' },
  container: { backgroundColor: '#ffffff', borderRadius: '8px', margin: '40px auto', padding: '0', maxWidth: '600px', boxShadow: '0 2px 8px rgba(0,0,0,0.08)' },
  header: { backgroundColor: '#1a1a2e', borderRadius: '8px 8px 0 0', padding: '32px', textAlign: 'center' as const },
  logoText: { color: '#e2c044', fontSize: '28px', fontWeight: '800', margin: '0', letterSpacing: '4px' },
  headerSub: { color: '#888', fontSize: '14px', margin: '4px 0 0' },
  main: { padding: '40px 48px' },
  heading: { fontSize: '26px', fontWeight: '700', color: '#1a1a2e', marginBottom: '20px' },
  greeting: { fontSize: '16px', color: '#444', marginBottom: '16px' },
  text: { fontSize: '16px', color: '#333', lineHeight: '1.6', marginBottom: '24px' },
  receiptCard: { backgroundColor: '#f9f9f9', border: '1px solid #e0e0e0', borderRadius: '8px', padding: '28px', marginBottom: '28px' },
  receiptTitle: { fontSize: '11px', color: '#888', letterSpacing: '2px', textTransform: 'uppercase' as const, marginBottom: '16px' },
  receiptHr: { borderColor: '#ddd', margin: '16px 0' },
  receiptRow: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' },
  receiptLabel: { fontSize: '14px', color: '#666' },
  receiptValue: { fontSize: '14px', color: '#222', fontWeight: '500' },
  receiptMono: { fontSize: '13px', color: '#555', fontFamily: 'monospace' },
  receiptTotalLabel: { fontSize: '16px', color: '#222', fontWeight: '700' },
  receiptTotalValue: { fontSize: '20px', color: '#1a1a2e', fontWeight: '800' },
  smallText: { fontSize: '13px', color: '#888', textAlign: 'center' as const, lineHeight: '1.6' },
  hr: { borderColor: '#eee', margin: '32px 0' },
  footer: { padding: '0 48px 32px', textAlign: 'center' as const },
  footerText: { fontSize: '13px', color: '#aaa', marginBottom: '6px' },
  link: { color: '#e2c044', textDecoration: 'none' },
};
